 {"id":"bd-1tz6","title":"Implement HeadlessTerm in-memory terminal","description":"# Implement HeadlessTerm in-memory terminal

## Background
Part of Headless Rendering Mode (bd-3m7u). In-memory terminal for CI testing without PTY.

## Technical Design

```rust
/// Headless terminal for testing
pub struct HeadlessTerm {
    /// In-memory screen buffer
    screen: Buffer,
    /// Virtual cursor position
    cursor: (u16, u16),
    /// Captured raw output
    raw_output: Vec<u8>,
    /// Current style state
    style_state: StyleState,
    /// Terminal size
    size: (u16, u16),
    /// Capabilities (configurable)
    capabilities: TerminalCapabilities,
}

impl HeadlessTerm {
    pub fn new(width: u16, height: u16) -> Self {
        Self {
            screen: Buffer::empty(Rect::new(0, 0, width, height)),
            cursor: (0, 0),
            raw_output: Vec::new(),
            style_state: StyleState::default(),
            size: (width, height),
            capabilities: TerminalCapabilities::full(),
        }
    }

    /// Process ANSI output and update screen
    pub fn process(&mut self, output: &[u8]) {
        self.raw_output.extend_from_slice(output);

        let mut parser = AnsiParser::new();
        for action in parser.parse(output) {
            self.apply_action(action);
        }
    }

    fn apply_action(&mut self, action: AnsiAction) {
        match action {
            AnsiAction::Print(c) => {
                let (x, y) = self.cursor;
                if x < self.size.0 {
                    self.screen.set(x, y, Cell::new(c).style(self.style_state.to_style()));
                    self.cursor.0 += 1;
                }
            }
            AnsiAction::MoveTo(x, y) => {
                self.cursor = (x.min(self.size.0), y.min(self.size.1));
            }
            AnsiAction::SetFg(color) => {
                self.style_state.fg = Some(color);
            }
            AnsiAction::SetBg(color) => {
                self.style_state.bg = Some(color);
            }
            AnsiAction::Reset => {
                self.style_state = StyleState::default();
            }
            AnsiAction::ClearScreen => {
                self.screen.clear();
            }
            AnsiAction::ClearLine => {
                let y = self.cursor.1;
                for x in 0..self.size.0 {
                    self.screen.set(x, y, Cell::default());
                }
            }
            // ... other actions
        }
    }

    /// Get screen as text lines
    pub fn screen_text(&self) -> Vec<String> {
        (0..self.size.1)
            .map(|y| {
                (0..self.size.0)
                    .map(|x| self.screen.get(x, y).content.to_char())
                    .collect()
            })
            .collect()
    }

    /// Assert screen matches expected
    pub fn assert_matches(&self, expected: &[&str]) {
        let actual = self.screen_text();
        for (y, (actual_line, expected_line)) in actual.iter().zip(expected).enumerate() {
            let actual_trimmed = actual_line.trim_end();
            let expected_trimmed = expected_line.trim_end();
            assert_eq!(
                actual_trimmed, expected_trimmed,
                "Mismatch at line {}: expected {:?}, got {:?}",
                y, expected_trimmed, actual_trimmed
            );
        }
    }

    /// Export for debugging
    pub fn dump(&self) -> String {
        self.screen_text().join("\n")
    }
}
```

