+        let has_down = events.iter().any(|e| {
+            matches!(
+                e,
+                Event::Key(KeyEvent {
+                    code: KeyCode::Down,
+                    ..
+                })
+            )
+        });
+        assert!(
+            has_down,
+            "Down arrow split across writes should be parsed: {events:?}"
+        );
+    }
